mapper.select:
SELECT w.warning_id AS alertId, w.warning_time AS warningTime, w.patient_name AS patientName, CASE WHEN w.gender IS NOT NULL AND w.gender != '' THEN w.gender WHEN p.gender = 1 THEN '男' WHEN p.gender = 2 THEN '女' ELSE '未知' END AS genderText, COALESCE(w.age, p.age) AS age, CONCAT( w.patient_name, ' / ', CASE WHEN w.gender IS NOT NULL AND w.gender != '' THEN w.gender WHEN p.gender = 1 THEN '男' WHEN p.gender = 2 THEN '女' ELSE '未知' END, ' / ', COALESCE(COALESCE(w.age, p.age), 0), '岁' ) AS patientInfo, w.inpatient_no AS inpatientNo, w.dept_name AS wardName, w.warning_type AS warningType, w.warning_level AS alertLevel, CASE w.warning_level WHEN 1 THEN '低危' WHEN 2 THEN '中危' WHEN 3 THEN '高危' ELSE '未知' END AS alertLevelText, w.handle_status AS alertStatus, CASE w.handle_status WHEN 0 THEN '待确认' WHEN 1 THEN '待处理' WHEN 2 THEN '处理中' WHEN 3 THEN '已处理' WHEN 4 THEN '已忽略' ELSE '未知' END AS alertStatusText, w.handle_time AS handleTime FROM ecg_abnormal_warning w LEFT JOIN patient_info p ON w.patient_id = p.patient_id AND p.is_deleted = 0 WHERE w.is_deleted = 0
AND ( w.patient_name LIKE CONCAT('%', #{req.keyword}, '%') OR w.inpatient_no LIKE CONCAT('%', #{req.keyword}, '%') )
AND ( w.dept_name = #{req.ward} OR CAST(w.dept_id AS CHAR) = #{req.ward} )
AND w.warning_level = #{alertLevelCode}
AND w.handle_status = #{alertStatusCode}
AND w.warning_time >= #{startTime}
AND w.warning_time <= #{endTime}
ORDER BY w.warning_time DESC, w.warning_id DESC
